            "content": "#!/bin/bash\nfor utilisateur in $(cat /tmp/users.txt); do\n    if id \"$utilisateur\" &> /dev/null; then\n        echo \"$utilisateur existe déjà\"\n    else\n        useradd -m \"$utilisateur\"\n        echo \"Utilisateur $utilisateur créé\"\n    fi\ndone"
